// 2.7.1 | 2021-12-19 | raj | DFCT0010296 - HHS: If user is in two OU and is remove/deleted from their default/primary OU, their default OU is not updated. 
// Script Continued Below
(function executeRule(current, previous /*null when async*/ ) {

    var OrganizationalOU = new OrganizationalScripts();
    OrganizationalOU.RemoveMemberAsTaskingAuthority(current.discover_office_hierarchy + '', current.office_member + '');
	//STRY0059849 - making OU HA similar to TM
	OrganizationalOU.RemoveMemberAsOUHierarchyAdmin(current.discover_office_hierarchy + '', current.office_member + '');
    // STRY0046028, STRY0085149
    var UserPermissions = new UserInfoScripts();

	// DFCT0010296 - if the member was removed from thier default OU, set another default OU
	if(current.u_isdefaultou){
		UserPermissions.setNewDefaultOU(current.office_member);
	}

    // before removing global roles, determine if the user has been removed from all OU's
    var grMemOUs = new GlideRecordSecure("x_153465_discovert_discover_office_members");
    grMemOUs.addQuery('office_member', current.office_member + '');
    grMemOUs.query();
    // if there are still OUs this member is in, do not remove global roles.  If not, remove global roles.
    if (!grMemOUs.next()) {

        if (UserPermissions.removeRole(current.office_member, 'is_tasker_application_admin', 'x_153465_discovert.tasker_application_admin', 'GlobalRole'))
            gs.addInfoMessage('Role: x_153465_discovert.tasker_application_admin - removed from user: ' + current.office_member.first_name + ' ' +
                current.office_member.middle_name + ' ' + current.office_member.last_name);

        if (UserPermissions.removeRole(current.office_member, 'is_global_tasking_authority', 'x_153465_discovert.tasker_global_Tasking_Authority_member_admin', 'GlobalRole'))
            gs.addInfoMessage('Role: x_153465_discovert.tasker_global_Tasking_Authority_member_admin - removed from user: ' + current.office_member.first_name + ' ' +
                current.office_member.middle_name + ' ' + current.office_member.last_name);

		// STRY0112585 - Task Executive- Update for New Member Form
        if (UserPermissions.removeRole(current.office_member, 'is_task_executive', 'x_153465_discovert.Task_Executive', 'GlobalRole'))
            gs.addInfoMessage('Role: x_153465_discovert.Task_Executive - removed from user: ' + current.office_member.first_name + ' ' +
                current.office_member.middle_name + ' ' + current.office_member.last_name);


        if (UserPermissions.removeRole(current.office_member, 'user_is_organization_admin', 'x_153465_discovert.tasker_organizational_admin', 'GlobalRole'))
            gs.addInfoMessage('Role: x_153465_discovert.tasker_organizational_admin - removed from user: ' + current.office_member.first_name + ' ' +
                current.office_member.middle_name + ' ' + current.office_member.last_name);

        // This was a global role.  Remove from any user taken out of the system.  The role is no longer used.  So, this stays global
        if (UserPermissions.removeRole(current.office_member, '', 'x_153465_discovert.tasker_single_ou_admin', 'GlobalRole'))
            gs.addInfoMessage('Role: x_153465_discovert.tasker_single_ou_admin - removed from user: ' + current.office_member.first_name + ' ' +
                current.office_member.middle_name + ' ' + current.office_member.last_name);

        // This was a global role.  Remove from any user taken out of the system.  The role is no longer used.  So, this stays global
        if (UserPermissions.removeRole(current.office_member, '', 'x_153465_discovert.tasker_single_ou_member_admin', 'GlobalRole'))
            gs.addInfoMessage('Role: x_153465_discovert.tasker_single_ou_member_admin - removed from user: ' + current.office_member.first_name + ' ' +
                current.office_member.middle_name + ' ' + current.office_member.last_name);

        if (UserPermissions.removeRole(current.office_member, 'can_manage_process_permissions', 'x_153465_discovert.tasker_process_template_admin', 'GlobalRole'))
            gs.addInfoMessage('Role: x_153465_discovert.tasker_process_template_admin - removed from user: ' + current.office_member.first_name + ' ' +
                current.office_member.middle_name + ' ' + current.office_member.last_name);

        if (UserPermissions.removeRole(current.office_member, 'can_manage_global_processes', 'x_153465_discovert.tasker_process_template_global', 'GlobalRole'))
            gs.addInfoMessage('Role: x_153465_discovert.tasker_process_template_global - removed from user: ' + current.office_member.first_name + ' ' +
                current.office_member.middle_name + ' ' + current.office_member.last_name);

        // // STRY0076016 - ROLE NOT NEEDED
        if (UserPermissions.removeRole(current.office_member, 'has_ou_process_rights', 'x_153465_discovert.tasker_process_template_ou', 'GlobalRole'))
            gs.addInfoMessage('Role: x_153465_discovert.tasker_process_template_ou - removed from user: ' + current.office_member.first_name + ' ' +
                current.office_member.middle_name + ' ' + current.office_member.last_name);

        if (UserPermissions.removeRole(current.office_member, 'has_personal_process_rights', 'x_153465_discovert.tasker_process_template_user', 'GlobalRole'))
            gs.addInfoMessage('Role: x_153465_discovert.tasker_process_template_user - removed from user: ' + current.office_member.first_name + ' ' +
                current.office_member.middle_name + ' ' + current.office_member.last_name);

        if (UserPermissions.removeRole(current.office_member, 'can_import_ou_hierarchy', 'x_153465_discovert.tasker_hierarchy_import_user', 'GlobalRole'))
            gs.addInfoMessage('Role: x_153465_discovert.tasker_hierarchy_import_user - removed from user: ' + current.office_member.first_name + ' ' +
                current.office_member.middle_name + ' ' + current.office_member.last_name);

        // this user has been deleted.
        // Moved to the end so removed last when all roles that inherit it are released
        if (UserPermissions.removeRole(current.office_member, '', 'x_153465_discovert.tasker_user', 'GlobalRole'))
            gs.addInfoMessage('Role: x_153465_discovert.tasker_user - removed from user: ' + current.office_member.first_name + ' ' +
                current.office_member.middle_name + ' ' + current.office_member.last_name);
    }
})(current, previous);
